//	WHERE dprv.organization_id = ? AND dprv.business_unit_id = ?
//
// Returns the same *bun.SelectQuery so it can be chained fluently:
//
//	buncolgen.RuleVersionScopeTenant(sq, ti).
//		Where(buncolgen.RuleVersionColumns.ID.Eq(), id)
func RuleVersionScopeTenant(q *bun.SelectQuery, ti pagination.TenantInfo) *bun.SelectQuery {
	return ScopeTenant(q, RuleVersionColumns.OrganizationID, RuleVersionColumns.BusinessUnitID, ti)
}

// RuleVersionScopeTenantUpdate restricts an update query to a single tenant.
// Use this inside UpdateQuery.WhereGroup callbacks:
//
//	WhereGroup(" AND ", func(uq *bun.UpdateQuery) *bun.UpdateQuery {
//		return buncolgen.RuleVersionScopeTenantUpdate(uq, req.TenantInfo).
//			Where(buncolgen.RuleVersionColumns.ID.In(), bun.List(ids))
//	})
func RuleVersionScopeTenantUpdate(q *bun.UpdateQuery, ti pagination.TenantInfo) *bun.UpdateQuery {
	return ScopeTenantUpdate(q, RuleVersionColumns.OrganizationID, RuleVersionColumns.BusinessUnitID, ti)
}

// RuleVersionScopeTenantDelete restricts a delete query to a single tenant.
// Use this inside DeleteQuery.WhereGroup callbacks:
//
//	WhereGroup(" AND ", func(dq *bun.DeleteQuery) *bun.DeleteQuery {
//		return buncolgen.RuleVersionScopeTenantDelete(dq, req.TenantInfo).
//			Where(buncolgen.RuleVersionColumns.ID.Eq(), id)
//	})
func RuleVersionScopeTenantDelete(q *bun.DeleteQuery, ti pagination.TenantInfo) *bun.DeleteQuery {
	return ScopeTenantDelete(q, RuleVersionColumns.OrganizationID, RuleVersionColumns.BusinessUnitID, ti)
}

// RuleVersionApplyTenant returns a closure for SelectQuery.Apply() that scopes to a single tenant.
// Use this instead of wrapping ScopeTenant in an anonymous function:
//
//	q.Apply(buncolgen.RuleVersionApplyTenant(tenantInfo))
func RuleVersionApplyTenant(ti pagination.TenantInfo) func(*bun.SelectQuery) *bun.SelectQuery {
	return ApplyTenant(RuleVersionColumns.OrganizationID, RuleVersionColumns.BusinessUnitID, ti)
}

